import java.io.*;
import java.util.*;

public class Main {
    private static int countLessOrEqual(int[] row, int x) {
        int lo = 0, hi = row.length;
        while (lo < hi) {
            int mid = (lo + hi) >>> 1;
            if (row[mid] <= x) {
                lo = mid + 1;
            } else {
                hi = mid;
            }
        }
        return lo; // number of elements <= x
    }

    public static void main(String[] args) throws Exception {
        // Read entire input as a single string to handle both real newlines and literal "\\n"
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        int c;
        while ((c = br.read()) != -1) {
            raw.append((char) c);
        }
        // Replace literal "\\n" sequences with spaces, also normalize whitespace
        String data = raw.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(data);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            int[][] mat = new int[N][M];
            int min = Integer.MAX_VALUE;
            int max = Integer.MIN_VALUE;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    int val = Integer.parseInt(st.nextToken());
                    mat[i][j] = val;
                    if (val < min) min = val;
                    if (val > max) max = val;
                }
            }
            int desired = (N * M) / 2;
            int low = min, high = max;
            while (low <= high) {
                int mid = low + ((high - low) >>> 1);
                int cnt = 0;
                for (int i = 0; i < N; i++) {
                    cnt += countLessOrEqual(mat[i], mid);
                }
                if (cnt <= desired) {
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            out.append(low);
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

